using Microsoft.EntityFrameworkCore;
using verii_metivon_api.Core.Auth;
using verii_metivon_api.Core.Paging;
using verii_metivon_api.Core.UnitOfWork;
using verii_metivon_api.Modules.Accounting.Application.Parameters;
using verii_metivon_api.Modules.Accounting.Domain.Entities;
using verii_metivon_api.Modules.Inventory.Domain.Entities;
using verii_metivon_api.Modules.Inventory.Domain.Enums;
using verii_metivon_api.Modules.Products.Domain.Enums;
namespace verii_metivon_api.Modules.Inventory.Application.Services;
public sealed class InventoryService(IUnitOfWork u, IAccountingParameterService accountingParameters) : IInventoryService
{
    public async Task<ApiResponse<PagedResult<InventoryTransactionRow>>> GetTransactionsAsync(InventoryTransactionQuery q, CancellationToken ct) { var x = u.Repository<InventoryTransaction>().Query().Include(v => v.Product).Include(v => v.Warehouse).Include(v => v.StorageLocation).Include(v => v.InventoryLot).Include(v => v.InventorySerial).AsQueryable(); if (q.ProductId.HasValue) x = x.Where(v => v.ProductId == q.ProductId); if (q.WarehouseId.HasValue) x = x.Where(v => v.WarehouseId == q.WarehouseId); if (q.LocationId.HasValue) x = x.Where(v => v.StorageLocationId == q.LocationId); if (q.MovementType.HasValue) x = x.Where(v => v.MovementType == q.MovementType); if (q.FromDate.HasValue) x = x.Where(v => v.PostingDate >= q.FromDate); if (q.ToDate.HasValue) x = x.Where(v => v.PostingDate <= q.ToDate); if (!string.IsNullOrWhiteSpace(q.Search)) { var s = q.Search.Trim(); x = x.Where(v => v.DocumentNumber.Contains(s) || v.Product.Code.Contains(s) || v.Product.Name.Contains(s)); } x = x.ApplyPagedFilters(q); var total = await x.CountAsync(ct); var items = await x.OrderByDescending(v => v.PostingDate).ThenByDescending(v => v.Id).Skip((q.NormalizedPageNumber - 1) * q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v => new InventoryTransactionRow(v.Id, v.PostingId, v.DocumentType, v.DocumentNumber, v.PostingDate, v.MovementType.ToString(), v.Product.Code, v.Product.Name, v.Warehouse.Code, v.StorageLocation.Code, v.InventoryLot != null ? v.InventoryLot.LotNumber : null, v.InventorySerial != null ? v.InventorySerial.SerialNumber : null, v.BaseQuantity * (int)v.Direction, v.UnitCost, v.TotalCost)).ToListAsync(ct); return ApiResponse<PagedResult<InventoryTransactionRow>>.Ok(new(items, q.NormalizedPageNumber, q.NormalizedPageSize, total)); }
    public async Task<ApiResponse<PagedResult<InventoryBalanceRow>>> GetBalancesAsync(InventoryBalanceQuery q, CancellationToken ct) { var x = u.Repository<InventoryBalance>().Query().Join(u.Repository<verii_metivon_api.Modules.Products.Domain.Entities.Product>().Query(), b => b.ProductId, p => p.Id, (b, p) => new { b, p }).Join(u.Repository<verii_metivon_api.Modules.Warehouses.Domain.Entities.Warehouse>().Query(), a => a.b.WarehouseId, w => w.Id, (a, w) => new { a.b, a.p, w }).Join(u.Repository<verii_metivon_api.Modules.Warehouses.Domain.Entities.StorageLocation>().Query(), a => a.b.StorageLocationId, l => l.Id, (a, l) => new { a.b, a.p, a.w, l }).Join(u.Repository<InventoryStatus>().Query(), a => a.b.InventoryStatusId, s => s.Id, (a, s) => new { a.b, a.p, a.w, a.l, s }); if (q.ProductId.HasValue) x = x.Where(v => v.b.ProductId == q.ProductId); if (q.WarehouseId.HasValue) x = x.Where(v => v.b.WarehouseId == q.WarehouseId); if (q.LocationId.HasValue) x = x.Where(v => v.b.StorageLocationId == q.LocationId); if (q.AvailableOnly) x = x.Where(v => v.s.IsAvailable && v.b.AvailableQuantity > 0); if (!string.IsNullOrWhiteSpace(q.Search)) { var z = q.Search.Trim(); x = x.Where(v => v.p.Code.Contains(z) || v.p.Name.Contains(z) || v.l.Code.Contains(z)); } x = x.ApplyPagedFilters(q); var total = await x.CountAsync(ct); var baseRows = await x.OrderBy(v => v.p.Code).ThenBy(v => v.w.Code).ThenBy(v => v.l.Code).Skip((q.NormalizedPageNumber - 1) * q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v => new { v.b, v.p, v.w, v.l, v.s }).ToListAsync(ct); var lotIds = baseRows.Where(v => v.b.InventoryLotId.HasValue).Select(v => v.b.InventoryLotId!.Value).Distinct().ToArray(); var serialIds = baseRows.Where(v => v.b.InventorySerialId.HasValue).Select(v => v.b.InventorySerialId!.Value).Distinct().ToArray(); var lots = await u.Repository<InventoryLot>().Query().Where(v => lotIds.Contains(v.Id)).ToDictionaryAsync(v => v.Id, ct); var serials = await u.Repository<InventorySerial>().Query().Where(v => serialIds.Contains(v.Id)).ToDictionaryAsync(v => v.Id, ct); var items = baseRows.Select(v => new InventoryBalanceRow(v.b.Id, v.p.Id, v.p.Code, v.p.Name, v.w.Id, v.w.Code, v.l.Id, v.l.Code, v.s.Name, v.b.InventoryLotId.HasValue && lots.TryGetValue(v.b.InventoryLotId.Value, out var lot) ? lot.LotNumber : null, v.b.InventorySerialId.HasValue && serials.TryGetValue(v.b.InventorySerialId.Value, out var serial) ? serial.SerialNumber : null, v.b.InventoryLotId.HasValue && lots.TryGetValue(v.b.InventoryLotId.Value, out var exp) ? exp.ExpiryDate : null, v.b.PhysicalQuantity, v.b.ReservedQuantity, v.s.IsAvailable ? v.b.AvailableQuantity : 0, v.b.InventoryValue)).ToList(); return ApiResponse<PagedResult<InventoryBalanceRow>>.Ok(new(items, q.NormalizedPageNumber, q.NormalizedPageSize, total)); }
    public async Task<ApiResponse<PostInventoryResult>> PostAsync(PostInventoryRequest r, CancellationToken ct) { if (string.IsNullOrWhiteSpace(r.IdempotencyKey) || r.Lines.Count == 0) return ApiResponse<PostInventoryResult>.Error("Posting key and lines are required.", 400); if (await u.Repository<InventoryTransaction>().ExistsAsync(x => x.IdempotencyKey.StartsWith(r.IdempotencyKey + ":"), ct)) { var old = await u.Repository<InventoryTransaction>().Query().Where(x => x.IdempotencyKey.StartsWith(r.IdempotencyKey + ":")).OrderBy(x => x.Id).ToListAsync(ct); return ApiResponse<PostInventoryResult>.Ok(new(old[0].PostingId, old.Select(x => x.Id).ToList()), "Already posted."); } var postingId = Guid.NewGuid(); var ids = new List<long>(); await u.ExecuteInTransactionAsync(async token => { for (var i = 0; i < r.Lines.Count; i++) { var line = r.Lines[i]; if (line.Quantity <= 0) throw new InvalidOperationException("Quantity must be positive."); var product = await u.Repository<verii_metivon_api.Modules.Products.Domain.Entities.Product>().GetByIdAsync(line.ProductId, token) ?? throw new InvalidOperationException("Product not found."); if (product.TrackingType == InventoryTrackingType.Lot && !line.InventoryLotId.HasValue) throw new InvalidOperationException("Lot is required."); if (product.TrackingType == InventoryTrackingType.Serial && (!line.InventorySerialId.HasValue || line.Quantity != 1)) throw new InvalidOperationException("Serial tracked quantity must be one."); var balance = await u.Repository<InventoryBalance>().FirstOrDefaultAsync(x => x.ProductId == line.ProductId && x.WarehouseId == line.WarehouseId && x.StorageLocationId == line.StorageLocationId && x.InventoryStatusId == line.InventoryStatusId && x.InventoryLotId == line.InventoryLotId && x.InventorySerialId == line.InventorySerialId, true, token); if (balance is null) { balance = new InventoryBalance { ProductId = line.ProductId, WarehouseId = line.WarehouseId, StorageLocationId = line.StorageLocationId, InventoryStatusId = line.InventoryStatusId, InventoryLotId = line.InventoryLotId, InventorySerialId = line.InventorySerialId }; await u.Repository<InventoryBalance>().AddAsync(balance, token); } var signed = line.Quantity * (int)r.Direction; var next = balance.PhysicalQuantity + signed; var warehouse = await u.Repository<verii_metivon_api.Modules.Warehouses.Domain.Entities.Warehouse>().GetByIdAsync(line.WarehouseId, token) ?? throw new InvalidOperationException("Warehouse not found."); if (next < 0 && !warehouse.AllowNegativeStock) throw new InvalidOperationException("Insufficient inventory."); var settings = await accountingParameters.ResolveSettingsAsync(warehouse.BranchId, line.WarehouseId, token); if (settings.RequireInventoryPostingProfile && !await u.Repository<InventoryPostingProfile>().ExistsAsync(x => x.IsActive && x.MovementType == r.MovementType && (x.WarehouseId == null || x.WarehouseId == line.WarehouseId) && (x.ProductGroupId == null || x.ProductGroupId == product.ProductGroupId), token)) throw new InvalidOperationException("An active inventory posting profile is required by accounting parameters."); var cost = Math.Round(line.UnitCost ?? (balance.PhysicalQuantity > 0 ? balance.InventoryValue / balance.PhysicalQuantity : 0), settings.CostDecimalPlaces, MidpointRounding.AwayFromZero); var nextValue = balance.InventoryValue + signed * cost; if (nextValue < 0 && !settings.AllowNegativeInventoryValue) throw new InvalidOperationException("Negative inventory value is disabled by accounting parameters."); var inventoryStatus = await u.Repository<InventoryStatus>().GetByIdAsync(line.InventoryStatusId, token) ?? throw new InvalidOperationException("Inventory status not found."); balance.PhysicalQuantity = next; balance.AvailableQuantity = inventoryStatus.IsAvailable ? next - balance.ReservedQuantity : 0; balance.InventoryValue = nextValue; var tx = new InventoryTransaction { PostingId = postingId, IdempotencyKey = $"{r.IdempotencyKey}:{i}", DocumentType = r.DocumentType, DocumentId = r.DocumentId, DocumentLineId = line.DocumentLineId, DocumentNumber = r.DocumentNumber, PostingDate = r.PostingDate, MovementType = r.MovementType, Direction = r.Direction, ProductId = line.ProductId, UnitId = line.UnitId, WarehouseId = line.WarehouseId, StorageLocationId = line.StorageLocationId, InventoryStatusId = line.InventoryStatusId, InventoryLotId = line.InventoryLotId, InventorySerialId = line.InventorySerialId, Quantity = line.Quantity, BaseQuantity = line.Quantity, UnitCost = cost, TotalCost = Math.Round(line.Quantity * cost, settings.CostDecimalPlaces, MidpointRounding.AwayFromZero), CurrencyCode = r.CurrencyCode, Explanation = line.Explanation }; await u.Repository<InventoryTransaction>().AddAsync(tx, token); await u.SaveChangesAsync(token); ids.Add(tx.Id); if (r.Direction == InventoryMovementDirection.Receipt && settings.CreateCostLayersOnReceipt) { await u.Repository<InventoryCostLayer>().AddAsync(new InventoryCostLayer { ProductId = line.ProductId, WarehouseId = line.WarehouseId, ReceiptTransactionId = tx.Id, ReceiptDate = r.PostingDate, OriginalQuantity = line.Quantity, RemainingQuantity = line.Quantity, UnitCost = cost, CurrencyCode = r.CurrencyCode }, token); await u.SaveChangesAsync(token); } } }, ct); return ApiResponse<PostInventoryResult>.Ok(new(postingId, ids), "Inventory posted."); }
}


